<template>
  <div class="hello">
    <h1>{{ msg }}</h1>
    <h5>Author:{{author}}</h5>
    <h5>Work_address:{{work_address}}</h5>
    <h5>E-mail:{{email}}</h5>
    <hr/>
    <div id="example-1">
      <button v-on:click="counter += 1">Add 1</button>
      <p>The button above has been clicked {{ counter }} times.</p>
    </div>
    <hr/>
    <div id="example-2">
      <!-- `greet` 是在下面定义的方法名 -->
      <button v-on:click="greet">Greet</button>
    </div>
    <hr/>
    <div id="example-3">
      <button v-on:click="say('hi')">Say hi</button>
      <button v-on:click="say('what')">Say what</button>
      <button v-on:click="warn('Form cannot be submitted yet.',$event)">Submit</button>
      <br/>
      <!--阻止单击事件继续传播-->
      <a v-on:click.stop="doThis"></a>
      <!--提交事件不在重载页面-->
      <form v-on:submit.prevent="onSubmint"></form>
      <!--修饰符可以串联-->
      <a v-on:click.stop.prevent="doThat"></a>
      <!--只有修饰符-->
      <form v-on:submit.prevent></form>
      <div v-on:click.capture="doThis"></div>
      <div v-on:click.self="doThat"></div>
      <!--点击事件只会触发一次-->
      <button v-on:click.once="say('点击事件只会触发一次')">点击事件只会触发一次</button>
    </div>
    <div id="model">
      <input v-model="message" placeholder="edit me">
      <p>Message you input:{{message}}</p>
      <br/>
      <input type="checkbox" id="checkbox" v-model="checked">
      <label for="checkbox">{{checked}}</label>
      <br/>
      <div id="example-4">
        <ul>
          <li>
            <input type="checkbox" id="apple" value="APPLE" v-model="checkNames">
            <label for="apple">APPLE</label>
          </li>
          <br/>
          <li>
            <input type="checkbox" id="orange" value="ORANGE" v-model="checkNames">
            <label for="orange">ORANGE</label>
          </li>
          <br/>
          <li>
            <input type="checkbox" id="pear" value="PEAR" v-model="checkNames">
            <label for="pear">PEAR</label>
          </li>
          <br/>
        </ul>
        <span>Checked names:{{checkNames}}</span>
      </div>
      <div id="example-5">
        <input type="radio" id="one" value="One" v-model="picked">
        <label for="one">One</label>
        <input type="radio" id="two" value="Two" v-model="picked">
        <label for="two">Two</label>
        <br/>
        <span>Checked names:{{picked}}</span>
      </div>
      <div id="example-6">
        <select v-model="selected">
          <option disabled value="">请选择</option>
          <option>A</option>
          <option>B</option>
          <option>C</option>
          <option>D</option>
          <option>E</option>
        </select>
        <span>Selected:{{selected}}</span>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'HelloWorld',
  // 数据提供
  data () {
    return {
      msg: 'Welcome to Your Vue.js App.(nixinsheng)' + new Date().toLocaleString(),
      author: '倪新生',
      work_address: 'BeiJing.CHINA',
      email: '1911398892@qq.com',
      counter: 0,
      message: '',
      checked: false,
      checkNames: [],
      picked: '',
      selected: ''

    }
  },
  // 方法提供
  methods: {
    // 计算属性getter
    reverseMessage: function () {
      // 'this'指向 vm实例
      console.log(this.msg)
      this.msg = this.msg.split('').reverse().join('')
      console.log(this.msg)
    },
    // 在'methods'对象中定义方法
    greet: function (event) {
      // 'this' 在方法里指向当前Vue实例
      alert('Hello' + this.msg + '！')
      // 'event'是原生DOM事件
      if (event) {
        alert(event.target.tagName)
      }
    },
    say: function (message) {
      alert(message)
    },
    warn: function (message, event) {
      // 现在我们可以访问原生事件对象
      if (event) event.preventDefault()
      alert(message)
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
  h1, h2 {
    font-weight: bold;
  }

  ul {
    list-style-type: none;
    padding: 0;
  }

  li {
    display: inline-block;
    margin: 0 10px;
  }

  a {
    color: #42b98F;
  }
</style>



